<template>
  <div>
    <div style="width: 100%; height: 36px; background-color: #fff; padding: 4px 12px;" v-if="!loading">
      <span style="font-size: 18px;">共有{{ judgeList.length }}位已注册评委</span>
      <a @click="$router.push({ name: 'judgeWhiteListManage' })" style="font-size: 18px; float: right;">设置评委白名单</a>
    </div>
    <div style="padding: 0 20px 20px;">
      <p style="text-align: center; margin: 10px;" v-if="judgeList.length > 0">点击评委查看详情</p>
      <a-row :gutter="[16, 16]">
        <a-col v-for="(item, index) in judgeList" :key="index" v-if="!loading" :xs="24" :sm="24" :md="12" :lg="12" :xl="8" :xxl="6">
          <a-card style="border-radius: 4px;">
            <div style="display: flex; width: 100%">
              <div style="width: calc(100% - 88px); margin-right: 8px;" class="item" @click="getVotedData(item.id)">
                <h2 style="margin: 0;">{{ item.name }}
                  <!-- <a-tag :color="item.status ? 'green' : 'red'" style="position: relative; top: -4px;">已注册</a-tag> -->
                </h2>
                <div>
                  <p>参与时间：{{ item.registrationTime | time }}</p>
                  <p style="color: orange;" v-if="item.unratedContestantsCount > 0">剩余{{ item.unratedContestantsCount }}个选手未评</p>
                  <p style="color: green;" v-else>已全部评完</p>
                  <p style="color: blue;">{{ item.groupName }}</p>
                </div>
              </div>
              <div style="width: 80px; display: flex; justify-content: center; align-items: center;">
                <div style="display: flex; flex-direction: column; gap: 12px; align-items: center;">
                  <a style="float: right; font-size: 16px; color: red;" @click="resetWLJ(item.name)">解除注册</a>
                  <a style="float: right; font-size: 16px;" @click="showGroupList(item.id)">修改分组</a>
                </div>
              </div>
            </div>
          </a-card>
        </a-col>
      </a-row>
    </div>
    <div style="height: calc(100vh - 48px); text-align: center; background-color: #fff; border-radius: 4px; margin-bottom: 20px; padding: 30px 50px;" v-if="loading">
      <a-spin />
    </div>
    <van-popup v-model="changeGroupShow" style="width: 90%;">
      <h2 style="text-align: center;margin: 10px;">请选择分组</h2>
      <van-cell style="text-align: center; height: 48px; font-size: 16px;" v-for="item in groupInfo" :key="item.id" :title="`${item.groupName}（权重为${item.weight}）`" @click="changeGroup(item.id)"/>
      <a-button style="width: 100%; height: 48px; border-radius: 0px" @click="changeGroupShow = false">取消</a-button>
    </van-popup>
  </div>
</template>
<script>
import { resetWhitelistJudge } from '@/api/judgeWhiteList'
import { getRegisteredJudgesInfo, updateGroup } from '@/api/judge'
import { voteGroupList } from '@/api/judgeGroup'
export default {
  data() {
    return {
      loading: false,
      judgeList: [],
      changeGroupShow: false,
      groupInfo: [],
      selectdJudge: null,
    }
  },
  mounted() {
    this.loadData()
  },
  watch: {
    changeGroupShow(newVal) {
      if (!newVal) {
        this.groupInfo = []
      }
    },
  },
  methods: {
    loadData() {
      this.loading = true
      getRegisteredJudgesInfo(this.$route.params.id).then(res => {
        this.judgeList = res
      }).finally(() => { this.loading = false })
    },
    resetWLJ(judgeName) {
      const beforeClose = (action, done) => {
        if (action === 'confirm') {
          resetWhitelistJudge(this.$route.params.id, judgeName).then(res => {
            this.$message.info(res)
            this.loadData()
            done()
          })
        } else {
          done()
        }
      }
      this.$dialog.confirm({
        title: '是否确认解除注册？',
        message: '该操作会删除该评委当前所有的已打分数据',
        confirmButtonText: '是',
        cancelButtonText: '否',
        beforeClose,
      }).catch(() => {})
    },
    showGroupList(judgeId) {
      this.changeGroupShow = true
      this.selectdJudge = judgeId
      voteGroupList(this.$route.params.id).then(res => {
        this.groupInfo = res.records
      })
    },
    changeGroup(groupId) {
      updateGroup(this.selectdJudge, groupId).then(res => {
        if (res.code !== 500) {
          this.loadData()
          this.$message.info(res)
          this.selectdJudge = null
          this.changeGroupShow = false
        }
      })
    },
    getVotedData(judgeId) {
      this.$router.push({
        name: 'judgeVotedData',
        query: {
          judgeId,
        },
      })
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 16px 16px 12px !important;
}
::v-deep .ant-divider-horizontal {
  margin: 12px 0;
}
::v-deep .van-dialog__header{
  padding-top: 12px;
}
.item p{
  margin: 0;
}
</style>
